import os
import psycopg2
import pandas as pd
from naive_bayes import *


def get_data_from_db():
    conn = psycopg2.connect(
        host="db",  
        dbname=os.getenv("POSTGRES_DB"),
        user=os.getenv("POSTGRES_USER"),
        password=os.getenv("POSTGRES_PASSWORD"),
        port=5432
    )
    # Fetch the prepared feature set for model training.
    # This table is generated by the analysis.py script and contains
    # aggregated sentiment scores and the corresponding price trend.
    query = """
        SELECT time_period, symbol,
               reddit, youtube, banknews, gnews, newsapi, telegram,
               price_trend
        FROM dwd.coin_trend_features_tb
        WHERE price_trend IS NOT NULL
        ORDER BY time_period;
    """
    df = pd.read_sql_query(query, conn)
    conn.close()

    return df


if __name__ == '__main__':

    df = get_data_from_db()
    symbol_list = ['BTC', 'ETH', 'DOGE']
    df = df[df['symbol']==symbol_list[0]][['reddit', 'youtube', 'banknews', 'gnews', 'newsapi', 'telegram', 'price_trend']]
    model, X_test, y_test = train_naive_bayes_model(df)

    test_features = pd.DataFrame([
        {
            "reddit": "pos_strong",
            "youtube": "neutral",
            "banknews": "pos_weak",
            "gnews": "neutral",
            "newsapi": "no_data",
            "telegram": "pos_strong"
        },
        {
            "reddit": "neg_weak",
            "youtube": "neg_strong",
            "banknews": "neutral",
            "gnews": "neg_weak",
            "newsapi": "neg_weak",
            "telegram": "no_data"
        }
    ])
    predict_with_explanation(model, test_features)